```scala
import scala.collection.mutable.PriorityQueue
import scala.collection.mutable.ListBuffer

def solve(grid: Array[Array[Long]], k: Long): Long = {
  val m = grid.length
  val n = grid(0).length

  val teleportLists = Array.ofDim[(Int, Int)](m, n)
  for (i <- 0 until m) {
    for (j <- 0 until n) {
      val currentVal = grid(i)(j)
      val list = ListBuffer[(Int, Int)]()
      for (x <- 0 until m) {
        for (y <- 0 until n) {
          if (grid(x)(y) <= currentVal) {
            list += (x, y)
          }
        }
      }
      teleportLists(i)(j) = list.toArray
    }
  }

  val pq = PriorityQueue[(Long, Int, Int, Int)]()
  pq += (0L, 0, 0, 0)

  val visited = Array.ofDim[Long](m, n, k + 1)
  for (i <- 0 until m) {
    for (j <- 0 until n) {
      for (t <- 0 until k + 1) {
        visited(i)(j)(t) = Long.MaxValue
      }
    }
  }
  visited(0)(0)(0) = 0L

  while (pq.nonEmpty) {
    val (cost, i, j, t) = pq.pop()
    if (i == m - 1 && j == n - 1) return cost

    if (j + 1 < n) {
      val new_i = i
      val new_j = j + 1
      val new_cost = cost + grid(new_i)(new_j)
      if (new_cost < visited(new_i)(new_j)(t)) {
        visited(new_i)(new_j)(t) = new_cost
        pq += (new_cost, new_i, new_j, t)
      }
    }

    if (i + 1 < m) {
      val new_i = i + 1
      val new_j = j
      val new_cost = cost + grid(new_i)(new_j)
      if (new_cost < visited(new_i)(new_j)(t)) {
        visited(new_i)(new_j)(t) = new_cost
        pq += (new_cost, new_i, new_j, t)
      }
    }

    if (t < k) {
      for ((x, y) <- teleportLists(i)(j)) {
        val new_t = t + 1
        if (cost < visited(x)(y)(new_t)) {
          visited(x)(y)(new_t) = cost
          pq += (cost, x, y, new_t)
        }
      }
    }
  }

  -1L
}
