import scala.collection.mutable.PriorityQueue

def solve(grid: Array[Array[Long]], k: Long): Long = {
  val m = grid.length
  val n = grid(0).length

  val teleportLists = Array.ofDim[Array[(Int, Int)]](m, n)
  for (i <- 0 until m) {
    for (j <- 0 until n) {
      teleportLists(i)(j) = Array()
      val currentVal = grid(i)(j)
      for (x <- 0 until m) {
        for (y <- 0 until n) {
          if (grid(x)(y) <= currentVal) {
            teleportLists(i)(j) = teleportLists(i)(j) :+ (x, y)
          }
        }
      }
    }
  }

  val pq = PriorityQueue[(Long, Int, Int, Int)]()
  pq.enqueue((0L, 0, 0, 0))

  val visited = Array.ofDim[Long](m, n, k + 1)
  for (i <- 0 until m) {
    for (j <- 0 until n) {
      for (t <- 0 until k + 1) {
        visited(i)(j)(t) = Long.MaxValue
      }
    }
  }
  visited(0)(0)(0) = 0L

  while (pq.nonEmpty) {
    val (cost, i, j, t) = pq.dequeue()
    if (i == m - 1 && j == n - 1) return cost

    if (j + 1 < n) {
      val newI = i
      val newJ = j + 1
      val newCost = cost + grid(newI)(newJ)
      if (newCost < visited(newI)(newJ)(t)) {
        visited(newI)(newJ)(t) = newCost
        pq.enqueue((newCost, newI, newJ, t))
      }
    }

    if (i + 1 < m) {
      val newI = i + 1
      val newJ = j
      val newCost = cost + grid(newI)(newJ)
      if (newCost < visited(newI)(newJ)(t)) {
        visited(newI)(newJ)(t) = newCost
        pq.enqueue((newCost, newI, newJ, t))
      }
    }

    if (t < k) {
      for ((x, y) <- teleportLists(i)(j)) {
        val newT = t + 1
        if (cost < visited(x)(y)(newT)) {
          visited(x)(y)(newT) = cost
          pq.enqueue((cost, x, y, newT))
        }
      }
    }
  }

  -1
}
